Greedy insertion minimizing marginal cost per unit load weighted by temporal urgency factor}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	for shipIdx := range oris {
		bestAssignIdx := -1
		bestScore := math.MaxFloat64
		var bestSavedState Assign
		loadWeight := 1.0
		if oris[shipIdx].Load > 0 {
			loadWeight = float64(oris[shipIdx].Load)
		}
		timeUrgency := 1.0
		if oris[shipIdx].TimeEnd > oris[shipIdx].TimeStart && oris[shipIdx].TimeEnd-oris[shipIdx].TimeStart > 0 {
			timeUrgency = 1.0 / float64(oris[shipIdx].TimeEnd-oris[shipIdx].TimeStart+1)
		}
		scoreDenominator := loadWeight * timeUrgency
		if scoreDenominator <= 0 {
			scoreDenominator = 1.0
		}
		savedStates := make([]Assign, dispatch.AssignsLen)
		for i := 0; i < dispatch.AssignsLen; i++ {
			savedStates[i] = dispatch.Assigns[i]
			ok := dispatch.Assigns[i].AddShip(total_ship+shipIdx, oris[shipIdx], dess[shipIdx])
			if ok {
				oldCost := savedStates[i].Cost
				dispatch.Assigns[i].GenRoute()
				newCost := dispatch.Assigns[i].Cost
				if newCost >= 0 && newCost-oldCost >= 0 {
					score := (newCost - oldCost) / scoreDenominator
					if score < bestScore {
						bestScore = score
						bestAssignIdx = i
						bestSavedState = savedStates[i]
					}
				}
				dispatch.Assigns[i].RemoveShip(total_ship + shipIdx)
				dispatch.Assigns[i].GenRoute()
			}
		}
		if bestAssignIdx != -1 {
			dispatch.Assigns[bestAssignIdx] = bestSavedState
			dispatch.Assigns[bestAssignIdx].AddShip(total_ship+shipIdx, oris[shipIdx], dess[shipIdx])
			dispatch.Assigns[bestAssignIdx].GenRoute()
		} else {
			inserted := false
			for i := 0; i < dispatch.AssignsLen; i++ {
				if dispatch.Assigns[i].AddShip(total_ship+shipIdx, oris[shipIdx], dess[shipIdx]) {
					dispatch.Assigns[i].GenRoute()
					inserted = true
					break
				}
			}
			if !inserted && dispatch.AssignsLen < MAXASSIGNS {
				idx := dispatch.AssignsLen
				dispatch.Assigns[idx].AddShip(total_ship+shipIdx, oris[shipIdx], dess[shipIdx])
				dispatch.Assigns[idx].GenRoute()
				dispatch.AssignsLen++
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

